","import React from "react";
import "./Navigation.css";

interface NavProps {
 currentView: string;
 navigateToView: (view: string, id?: string | null) => void;
}

const NAV_ITEMS = [
 { view: "home", label: "Home" },
 { view: "book-ticket", label: "Book Ticket" },
 { view: "student-pass", label: "Student Pass" },
 { view: "my-tickets", label: "My Tickets" },
 { view: "my-student-passes", label: "My Passes" },
 { view: "payment-history", label: "Payment History" },
 { view: "my-complaints", label: "My Complaints" },
 { view: "complaint", label: "Complaint" },
 { view: "admin-dashboard", label: "Admin Dashboard" }
];

export default function Navigation({ currentView, navigateToView }: NavProps) {
