 <div className="metro-nav__brand">Metro Ticket Booking</div>
 <ul className="metro-nav__list">
 {NAV_ITEMS.map(item => (
 <li
 key={item.view}
 className={`metro-nav__item ${
 currentView === item.view ? "metro-nav__item--active" : ""
 }`}
 >
