","const BASE_URL = "/api/now/table";

function getHeaders() {
 return {
 "Content-Type": "application/json",
 Accept: "application/json",
 "X-UserToken": (window as any).g_ck
 };
}

function buildUrl(table: string, sysId?: string): string {
 const path = sysId ? `${BASE_URL}/${table}/${sysId}` : `${BASE_URL}/${table}`;
 const url = new URL(path, window.location.origin);
 url.searchParams.set("sysparm_display_value", "all");
 return url.toString();
}

async function request(url: string, options?: RequestInit) {
 const res = await fetch(url, { headers: getHeaders(), ...options });
 if (!res.ok) throw new Error(`API error: ${res.status}`);
 return res.json();
}

export const MetroService = {
 async list(table: string, query?: string, limit?: number) {
 const url = new URL(`${BASE_URL}/${table}`, window.location.origin);
 url.searchParams.set("sysparm_display_value", "all");
 if (query) url.searchParams.set("sysparm_query", query);
 if (limit) url.searchParams.set("sysparm_limit", String(limit));
 const data = await request(url.toString());
 return data.result || [];
 },

 async get(table: string, sysId: string) {
 const data = await request(buildUrl(table, sysId));
 return data.result;
 },

 async create(table: string, body: Record<string, any>) {
 const data = await request(buildUrl(table), {
 method: "POST",
 body: JSON.stringify(body)
 });
 return data.result;
 },

 async update(table: string, sysId: string, body: Record<string, any>) {
 const data = await request(buildUrl(table, sysId), {
 method: "PATCH",
 body: JSON.stringify(body)
 });
 return data.result;
 },

 async getStations() {
 return this.list("x_1877508_metro_0_metro_stations", "active=true^ORDERBYstation_name");
 },

 async getFare(sourceId: string, destId: string) {
 const records = await this.list(
 "x_1877508_metro_0_metro_fare_matrix",
 `source_station=${sourceId}^destination_station=${destId}^active=true`
 );
 return records.length > 0 ? records[0] : null;
 },

 async getPassengerByUser() {
 const records = await this.list(
 "x_1877508_metro_0_metro_passenger",
 "user=javascript:gs.getUserID()"
 );
 return records.length > 0 ? records[0] : null;
 }
};
