","import React, { useState } from "react";
import { MetroService } from "../services/MetroService";
import { display } from "../utils/fields";
import "./Complaint.css";

interface ComplaintProps {
 navigateToView: (view: string, id?: string) => void;
}

const CATEGORIES = [
 "Service Delay",
 "Cleanliness",
 "Staff Behavior",
 "Technical Issue",
 "Safety Concern",
 "Other"
];

export default function Complaint({ navigateToView }: ComplaintProps) {
 const [category, setCategory] = useState("");
 const [description, setDescription] = useState("");
 const [submitting, setSubmitting] = useState(false);
 const [error, setError] = useState("");
 const [complaintNumber, setComplaintNumber] = useState("");

 async function handleSubmit(e: React.FormEvent) {
 e.preventDefault();
 setError("");
 if (!category || !description.trim()) {
 setError("All fields are required");
 return;
 }
 setSubmitting(true);
 try {
 const result = await MetroService.create("x_1877508_metro_0_metro_complaint", {
 issue_type: category,
 description: description.trim()
 });
 setComplaintNumber(display(result.complaint_number) || display(result.number));
 } catch {
 setError("Failed to submit complaint. Please try again.");
 } finally {
 setSubmitting(false);
 }
 }

 if (complaintNumber) {
 return (
 <div className="metro-complaint">
 <div className="metro-complaint__success">
 <h2>✅ Complaint Registered</h2>
 <p>Your complaint has been registered successfully.</p>
 <p className="metro-complaint__number">Reference: {complaintNumber}</p>
 <button className="metro-complaint__btn" onClick={() => navigateToView("home")}>
 Back to Home
 </button>
 </div>
 </div>
 );
 }

 return (
 <div className="metro-complaint">
 <h1 className="metro-complaint__title">Raise a Complaint</h1>
 <form className="metro-complaint__form" onSubmit={handleSubmit}>
 {error && <div className="metro-complaint__error">{error}</div>}
 <label className="metro-complaint__label">
 Complaint Category
 <select
 className="metro-complaint__select"
 value={category}
 onChange={e => setCategory(e.target.value)}
 >
 <option value="">Select category</option>
 {CATEGORIES.map(c => (
 <option key={c} value={c}>{c}</option>
 ))}
 </select>
 </label>
 <label className="metro-complaint__label">
 Description
 <textarea
 className="metro-complaint__textarea"
 value={description}
 onChange={e => setDescription(e.target.value)}
 maxLength={500}
 rows={5}
 placeholder="Describe your issue..."
 />
 <span className="metro-complaint__charcount">{description.length}/500</span>
 </label>
 <button className="metro-complaint__btn" type="submit" disabled={submitting}>
 {submitting ? "Submitting..." : "Submit Complaint"}
 </button>
 </form>
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./MyTickets.css";

interface MyTicketsProps {
 navigateToView: (view: string, id?: string) => void;
}

function statusClass(status: string): string {
 const s = status.toLowerCase();
 if (s === "confirmed" || s === "active") return "metro-tickets__badge--green";
 if (s === "pending") return "metro-tickets__badge--orange";
 if (s === "cancelled") return "metro-tickets__badge--red";
 return "";
}

export default function MyTickets({ navigateToView }: MyTicketsProps) {
 const [bookings, setBookings] = useState<any[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 async function fetchBookings() {
 try {
 const results = await MetroService.list(
 "x_1877508_metro_0_metro_booking",
 "ORDERBYDESCsys_created_on",
 20
 );
 setBookings(results);
 } catch (e) {
 console.error("Failed to fetch bookings", e);
 } finally {
 setLoading(false);
 }
 }
 fetchBookings();
 }, []);

 if (loading) {
 return (
 <div className="metro-tickets">
 <h1 className="metro-tickets__title">My Tickets</h1>
 <p className="metro-tickets__loading">Loading bookings...</p>
 </div>
 );
 }

 if (bookings.length === 0) {
 return (
 <div className="metro-tickets">
 <h1 className="metro-tickets__title">My Tickets</h1>
 <div className="metro-tickets__empty">
 <p>No tickets found. Book a ticket to see it here.</p>
 <button className="metro-tickets__btn" onClick={() => navigateToView("book-ticket")}>
 Book Ticket
 </button>
 </div>
 </div>
 );
 }

 return (
 <div className="metro-tickets">
 <h1 className="metro-tickets__title">My Tickets</h1>
 <div className="metro-tickets__list">
 {bookings.map(b => (
 <div key={value(b.sys_id)} className="metro-tickets__card">
 <div className="metro-tickets__card-header">
 <span className="metro-tickets__booking-num">
 {display(b.booking_number) || display(b.number)}
 </span>
 <span className={`metro-tickets__badge ${statusClass(value(b.booking_status))}`}>
 {display(b.booking_status)}
 </span>
 </div>
 <div className="metro-tickets__route">
 {display(b.source_station)} → {display(b.destination_station)}
 </div>
 <div className="metro-tickets__fields">
 <span>Passenger: {display(b.passenger)}</span>
 <span>Date: {display(b.journey_date)}</span>
 <span>Passengers: {display(b.passenger_count)}</span>
 <span>Fare: ₹{display(b.fare_amount)}</span>
 <span>Payment: {display(b.payment_status)}</span>
 </div>
 <button
 className="metro-tickets__details-btn"
 onClick={() => navigateToView("ticket-details", value(b.sys_id))}
 >
 View Details
 </button>
 </div>
 ))}
 </div>
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./TicketDetails.css";

interface TicketDetailsProps {
 recordId: string | null;
 navigateToView: (view: string, id?: string) => void;
}

export default function TicketDetails({ recordId, navigateToView }: TicketDetailsProps) {
 const [booking, setBooking] = useState<any>(null);
 const [payment, setPayment] = useState<any>(null);
 const [qrTicket, setQrTicket] = useState<any>(null);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 if (!recordId) { setLoading(false); return; }
 async function fetchDetails() {
 try {
 const bk = await MetroService.get("x_1877508_metro_0_metro_booking", recordId!);
 setBooking(bk);
 const [payments, qrTickets] = await Promise.all([
 MetroService.list("x_1877508_metro_0_metro_payment", `booking=${recordId}`),
 MetroService.list("x_1877508_metro_0_metro_qr_ticket", `booking=${recordId}`)
 ]);
 if (payments.length > 0) setPayment(payments[0]);
 if (qrTickets.length > 0) setQrTicket(qrTickets[0]);
 } catch (e) {
 console.error("Failed to fetch ticket details", e);
 } finally {
 setLoading(false);
 }
 }
 fetchDetails();
 }, [recordId]);

 if (loading) return <div className="metro-details"><p>Loading ticket details...</p></div>;
 if (!booking) return (
 <div className="metro-details">
 <p>Booking not found.</p>
 <button className="metro-details__back" onClick={() => navigateToView("my-tickets")}>
 ← Back to My Tickets
 </button>
 </div>
 );

 return (
 <div className="metro-details">
 <button className="metro-details__back" onClick={() => navigateToView("my-tickets")}>
 ← Back to My Tickets
 </button>
 <h1 className="metro-details__title">Ticket Details</h1>
 <div className="metro-details__sections">
 <section className="metro-details__section">
 <h3>Booking Information</h3>
 <dl className="metro-details__dl">
 <dt>Booking Number</dt><dd>{display(booking.booking_number) || display(booking.number)}</dd>
 <dt>Passenger</dt><dd>{display(booking.passenger)}</dd>
 <dt>Status</dt><dd>{display(booking.booking_status)}</dd>
 <dt>Payment Status</dt><dd>{display(booking.payment_status)}</dd>
 <dt>Booking Date</dt><dd>{display(booking.sys_created_on)}</dd>
 </dl>
 </section>
 <section className="metro-details__section">
 <h3>Journey Details</h3>
 <dl className="metro-details__dl">
 <dt>Source</dt><dd>{display(booking.source_station)}</dd>
 <dt>Destination</dt><dd>{display(booking.destination_station)}</dd>
 <dt>Travel Date</dt><dd>{display(booking.journey_date)}</dd>
 <dt>Passengers</dt><dd>{display(booking.passenger_count)}</dd>
 <dt>Fare</dt><dd>₹{display(booking.fare_amount)}</dd>
 </dl>
 </section>
 {payment && (
 <section className="metro-details__section">
 <h3>Payment Details</h3>
 <dl className="metro-details__dl">
 <dt>Payment ID</dt><dd>{display(payment.payment_id)}</dd>
 <dt>Method</dt><dd>{display(payment.payment_method)}</dd>
 <dt>Status</dt><dd>{display(payment.transaction_status)}</dd>
 <dt>Amount</dt><dd>₹{display(payment.amount)}</dd>
 <dt>Reference</dt><dd>{display(payment.transaction_reference)}</dd>
 </dl>
 </section>
 )}
 {qrTicket && (
 <section className="metro-details__section">
 <h3>QR Ticket</h3>
 <dl className="metro-details__dl">
 <dt>Ticket ID</dt><dd>{display(qrTicket.qr_ticket_id)}</dd>
 <dt>Ticket Status</dt><dd>{display(qrTicket.ticket_status)}</dd>
 <dt>Valid From</dt><dd>{display(qrTicket.valid_from)}</dd>
 <dt>Valid Until</dt><dd>{display(qrTicket.valid_until)}</dd>
 <dt>Entry Status</dt><dd>{display(qrTicket.entry_status)}</dd>
 <dt>Exit Status</dt><dd>{display(qrTicket.exit_status)}</dd>
 <dt>QR Code</dt><dd className="metro-details__qr">{display(qrTicket.qr_code_value)}</dd>
 </dl>
 </section>
 )}
 {!qrTicket && (
 <section className="metro-details__section">
 <h3>QR Ticket</h3>
 <p className="metro-details__no-qr">No QR ticket generated yet. Complete payment to generate QR ticket.</p>
 </section>
 )}
 </div>
 </div>
 );
}
