","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./PassDetails.css";

interface PassDetailsProps {
 navigateToView: (view: string, id?: string) => void;
}

export default function PassDetails({ navigateToView }: PassDetailsProps) {
 const [passes, setPasses] = useState<any[]>([]);
 const [loading, setLoading] = useState(true);
 const [message, setMessage] = useState("");

 async function fetchPasses() {
 try {
 const data = await MetroService.list(
 "x_1877508_metro_0_metro_student_pass",
 "ORDERBYDESCsys_created_on",
 20
 );
 setPasses(data);
 } catch (e) {
 console.error("Failed to fetch passes", e);
 } finally {
 setLoading(false);
 }
 }

 useEffect(() => { fetchPasses(); }, []);

 async function handleRenew(pass: any) {
 const today = new Date();
 const validFrom = today.toISOString().split("T")[0];
 const duration = value(pass.pass_type) === "quarterly" ? 90 : 30;
 const until = new Date(today.getTime() + duration * 86400000);
 const validUntil = until.toISOString().split("T")[0];

 try {
 await MetroService.create("x_1877508_metro_0_metro_student_pass", {
 student: value(pass.student),
 source_station: value(pass.source_station),
 destination_station: value(pass.destination_station),
 pass_type: value(pass.pass_type),
 valid_from: validFrom,
 valid_until: validUntil,
 payment_status: "pending",
 pass_status: "draft"
 });
 setMessage("Renewal request created successfully.");
 await fetchPasses();
 } catch (e) {
 setMessage("Failed to create renewal request.");
 }
 }

 if (loading) return <div className="metro-pass-details"><p>Loading passes...</p></div>;

 return (
 <div className="metro-pass-details">
 <h1 className="metro-pass-details__title">Student Passes</h1>
 {message && <p className="metro-pass-details__message">{message}</p>}
 {passes.length === 0 && <p>No student passes found.</p>}
 <div className="metro-pass-details__grid">
 {passes.map((pass) => (
 <div key={pass.sys_id.value} className="metro-pass-details__card">
 <div className="metro-pass-details__row"><span>Pass Number</span><span>{display(pass.pass_number) || display(pass.number)}</span></div>
 <div className="metro-pass-details__row"><span>Student</span><span>{display(pass.student)}</span></div>
 <div className="metro-pass-details__row"><span>Pass Type</span><span>{display(pass.pass_type)}</span></div>
 <div className="metro-pass-details__row"><span>Source</span><span>{display(pass.source_station)}</span></div>
 <div className="metro-pass-details__row"><span>Destination</span><span>{display(pass.destination_station)}</span></div>
 <div className="metro-pass-details__row"><span>Valid From</span><span>{display(pass.valid_from)}</span></div>
 <div className="metro-pass-details__row"><span>Valid Until</span><span>{display(pass.valid_until)}</span></div>
 <div className="metro-pass-details__row"><span>Amount</span><span>₹{display(pass.pass_amount)}</span></div>
 <div className="metro-pass-details__row"><span>Payment</span><span>{display(pass.payment_status)}</span></div>
 <div className="metro-pass-details__row"><span>Status</span><span>{display(pass.pass_status)}</span></div>
 <div className="metro-pass-details__row"><span>QR Ticket</span><span>{display(pass.qr_ticket)}</span></div>
 <button className="metro-pass-details__renew" onClick={() => handleRenew(pass)}>Renew Pass</button>
 </div>
 ))}
 </div>
 </div>
 );
}
