","import React from "react";

interface KPIData {
 totalBookings: number;
 totalPayments: number;
 totalRevenue: number;
 activePassCount: number;
 pendingVerifications: number;
 openComplaints: number;
 qrTickets: number;
}

interface AdminKPIsProps {
 data: KPIData;
 navigateToView: (view: string, id?: string) => void;
}

const KPI_ITEMS = [
 { key: "totalBookings", label: "Total Bookings", route: "admin-bookings", color: "#1a237e" },
 { key: "totalPayments", label: "Total Payments", route: "admin-payments", color: "#4caf50" },
 { key: "totalRevenue", label: "Total Revenue", route: "admin-payments", color: "#ff9800", prefix: "₹" },
 { key: "activePassCount", label: "Active Passes", route: "admin-student-passes", color: "#2196f3" },
 { key: "pendingVerifications", label: "Pending Verifications", route: "admin-student-verifications", color: "#9c27b0" },
 { key: "openComplaints", label: "Open Complaints", route: "admin-complaints", color: "#f44336" },
 { key: "qrTickets", label: "QR Tickets", route: "admin-qr-tickets", color: "#00bcd4" }
];

export default function AdminKPIs({ data, navigateToView }: AdminKPIsProps) {
 return (
 <div className="metro-admin__kpis">
 {KPI_ITEMS.map(item => (
 <div
 key={item.key}
 className="metro-admin__kpi-card metro-admin__kpi-card--clickable"
 style={{ borderLeftColor: item.color, cursor: "pointer" }}
 onClick={() => navigateToView(item.route)}
 role="button"
 tabIndex={0}
 onKeyDown={e => e.key === "Enter" && navigateToView(item.route)}
 >
 <span className="metro-admin__kpi-value">
 {item.prefix || ""}{(data as any)[item.key]}
 </span>
 <span className="metro-admin__kpi-label">{item.label}</span>
 </div>
 ))}
 </div>
 );
}
","import React, { useState, useEffect, useCallback } from "react";
import { MetroService } from "../services/MetroService";
import { value } from "../utils/fields";
import AdminKPIs from "./AdminKPIs";
import "./AdminDashboard.css";

interface AdminDashboardProps {
 navigateToView: (view: string, id?: string) => void;
}

export default function AdminDashboard({ navigateToView }: AdminDashboardProps) {
 const [kpiData, setKpiData] = useState<any>(null);
 const [loading, setLoading] = useState(true);

 const fetchData = useCallback(async () => {
 try {
 const [bk, py, cp, ps, vr, qr] = await Promise.all([
 MetroService.list("x_1877508_metro_0_metro_booking"),
 MetroService.list("x_1877508_metro_0_metro_payment"),
 MetroService.list("x_1877508_metro_0_metro_complaint"),
 MetroService.list("x_1877508_metro_0_metro_student_pass", "pass_status=active"),
 MetroService.list("x_1877508_metro_0_metro_student_profile", "verification_status=pending"),
 MetroService.list("x_1877508_metro_0_metro_qr_ticket")
 ]);
 const totalRevenue = py.reduce((s: number, p: any) => s + (parseFloat(value(p.amount)) || 0), 0);
 const openComplaints = cp.filter((c: any) => value(c.status) === "new" || value(c.status) === "in_progress").length;
 setKpiData({
 totalBookings: bk.length, totalPayments: py.length, totalRevenue,
 activePassCount: ps.length, pendingVerifications: vr.length,
 openComplaints, qrTickets: qr.length
 });
 } catch (e) { console.error("Dashboard load failed", e); }
 finally { setLoading(false); }
 }, []);

 useEffect(() => { fetchData(); }, [fetchData]);

 if (loading) return <div className="metro-admin"><p>Loading dashboard...</p></div>;

 return (
 <div className="metro-admin">
 <h1 className="metro-admin__title">Admin Dashboard</h1>
 <p style={{ color: "#666", marginBottom: "16px", fontSize: "14px" }}>Click any card to manage records</p>
 {kpiData && <AdminKPIs data={kpiData} navigateToView={navigateToView} />}
 </div>
 );
}
