import "./MyStudentPasses.css";

interface Props {
 navigateToView: (view: string, id?: string) => void;
}

export default function MyStudentPasses({ navigateToView }: Props) {
 const [passes, setPasses] = useState<any[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 async function fetch() {
 try {
 const data = await MetroService.list(
 "x_1877508_metro_0_metro_student_pass", "ORDERBYDESCsys_created_on", 20
 );
 setPasses(data);
 } catch (e) { console.error("Failed to fetch passes", e); }
 finally { setLoading(false); }
 }
 fetch();
 }, []);

 if (loading) return <div className="metro-passes"><p>Loading passes...</p></div>;

 if (passes.length === 0) {
 return (
 <div className="metro-passes">
 <h1 className="metro-passes__title">My Student Passes</h1>
 <p className="metro-passes__empty">No student passes found.</p>
 </div>
 );
 }

 return (
