 <div className="metro-passes__row"><span>Valid Until</span><span>{display(p.valid_until)}</span></div>
 <div className="metro-passes__row"><span>Amount</span><span>₹{display(p.pass_amount)}</span></div>
 <div className="metro-passes__row"><span>Payment</span><span>{display(p.payment_status)}</span></div>
 <div className="metro-passes__row"><span>Status</span><span>{display(p.pass_status)}</span></div>
 <div className="metro-passes__row"><span>QR Ticket</span><span>{display(p.qr_ticket)}</span></div>
 <button className="metro-passes__btn" onClick={() => navigateToView("pass-details", value(p.sys_id))}>
 View Pass Details
 </button>
 </div>
 ))}
 </div>
 </div>
 );
}
