","import React, { useState, useEffect, useCallback } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./AdminVerificationsList.css";

interface Props {
 navigateToView: (view: string, id?: string) => void;
}

export default function AdminVerificationsList({ navigateToView }: Props) {
 const [profiles, setProfiles] = useState<any[]>([]);
 const [loading, setLoading] = useState(true);
 const [message, setMessage] = useState<{ type: string; text: string } | null>(null);

 const fetchData = useCallback(async () => {
 try {
 const data = await MetroService.list(
 "x_1877508_metro_0_metro_student_profile", "ORDERBYDESCsys_created_on", 20
 );
 setProfiles(data);
 } catch (e) { console.error("Failed to fetch profiles", e); }
 finally { setLoading(false); }
 }, []);

 useEffect(() => { fetchData(); }, [fetchData]);

 async function handleStatusChange(sysId: string, newVal: string) {
 try {
 await MetroService.update("x_1877508_metro_0_metro_student_profile", sysId, { verification_status: newVal });
 setMessage({ type: "success", text: "Verification status updated successfully." });
 fetchData();
 } catch (e) {
 setMessage({ type: "error", text: "Failed to update verification status." });
 }
 }

 if (loading) return <div className="metro-admin-verify"><p>Loading profiles...</p></div>;

 return (
 <div className="metro-admin-verify">
 <button className="metro-admin-verify__back" onClick={() => navigateToView("admin-dashboard")}>← Back to Dashboard</button>
 <h1 className="metro-admin-verify__title">Student Verifications</h1>
 {message && <div className={`metro-admin-verify__msg--${message.type}`}>{message.text}</div>}
 <div className="metro-admin-verify__list">
 {profiles.map(p => (
 <div key={value(p.sys_id)} className="metro-admin-verify__card">
 <div className="metro-admin-verify__row"><span>Name</span><span>{display(p.student_name)}</span></div>
 <div className="metro-admin-verify__row"><span>User</span><span>{display(p.user)}</span></div>
 <div className="metro-admin-verify__row"><span>College</span><span>{display(p.college_name)}</span></div>
 <div className="metro-admin-verify__row"><span>Student ID</span><span>{display(p.student_id_number)}</span></div>
 <div className="metro-admin-verify__row"><span>Department</span><span>{display(p.department)}</span></div>
 <div className="metro-admin-verify__row"><span>Year</span><span>{display(p.year)}</span></div>
 <div className="metro-admin-verify__row"><span>Verified By</span><span>{display(p.verified_by)}</span></div>
 <div className="metro-admin-verify__row"><span>Verified Date</span><span>{display(p.verified_date)}</span></div>
 <div className="metro-admin-verify__action">
 <label>Status:</label>
 <select value={value(p.verification_status)} onChange={e => handleStatusChange(value(p.sys_id), e.target.value)}>
 <option value="pending">Pending</option>
 <option value="approved">Approved</option>
 <option value="rejected">Rejected</option>
 </select>
 </div>
 </div>
 ))}
 </div>
 </div>
 );
}
