 {complaints.map(c => (
 <div key={value(c.sys_id)} className="metro-admin-cpl__card">
 <div className="metro-admin-cpl__row"><span>Complaint #</span><span>{display(c.complaint_number) || display(c.number)}</span></div>
 <div className="metro-admin-cpl__row"><span>Passenger</span><span>{display(c.passenger)}</span></div>
 <div className="metro-admin-cpl__row"><span>Booking</span><span>{display(c.booking)}</span></div>
 <div className="metro-admin-cpl__row"><span>Student Pass</span><span>{display(c.student_pass)}</span></div>
 <div className="metro-admin-cpl__row"><span>Issue Type</span><span>{display(c.issue_type)}</span></div>
 <div className="metro-admin-cpl__row"><span>Description</span><span>{display(c.description)}</span></div>
 <div className="metro-admin-cpl__row"><span>Assigned To</span><span>{display(c.assigned_to)}</span></div>
 <div className="metro-admin-cpl__action">
 <label>Status:</label>
 <select value={value(c.status)} onChange={e => handleStatusChange(value(c.sys_id), e.target.value)}>
 <option value="new">New</option>
 <option value="in_progress">In Progress</option>
 <option value="resolved">Resolved</option>
 </select>
 </div>
 </div>
 ))}
 </div>
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./AdminDashboard.css";

interface Props {
 navigateToView: (view: string, id?: string) => void;
}

export default function AdminQRTicketsList({ navigateToView }: Props) {
 const [tickets, setTickets] = useState<any[]>([]);
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 async function fetch() {
 try {
 const data = await MetroService.list(
 "x_1877508_metro_0_metro_qr_ticket", "ORDERBYDESCsys_created_on", 20
 );
 setTickets(data);
 } catch (e) { console.error("Failed to fetch QR tickets", e); }
 finally { setLoading(false); }
 }
 fetch();
 }, []);

 if (loading) return <div className="metro-admin"><p>Loading QR tickets...</p></div>;

 return (
 <div className="metro-admin">
 <button className="metro-admin__back-btn" onClick={() => navigateToView("admin-dashboard")}>← Back to Dashboard</button>
 <h1 className="metro-admin__title">All QR Tickets</h1>
 <div className="metro-admin__cards">
 {tickets.map(t => (
 <div key={value(t.sys_id)} className="metro-admin__card">
 <div className="metro-admin__row"><span>QR Ticket ID</span><span>{display(t.qr_ticket_id)}</span></div>
 <div className="metro-admin__row"><span>Booking</span><span>{display(t.booking)}</span></div>
 <div className="metro-admin__row"><span>Student Pass</span><span>{display(t.student_pass)}</span></div>
 <div className="metro-admin__row"><span>QR Code</span><span>{display(t.qr_code_value)}</span></div>
 <div className="metro-admin__row"><span>Valid From</span><span>{display(t.valid_from)}</span></div>
 <div className="metro-admin__row"><span>Valid Until</span><span>{display(t.valid_until)}</span></div>
 <div className="metro-admin__row"><span>Entry Status</span><span>{display(t.entry_status)}</span></div>
 <div className="metro-admin__row"><span>Exit Status</span><span>{display(t.exit_status)}</span></div>
 <div className="metro-admin__row"><span>Ticket Status</span><span>{display(t.ticket_status)}</span></div>
 </div>
 ))}
 </div>
 </div>
 );
}
","import React, { useState, useEffect, useCallback } from "react";
import Navigation from "./components/Navigation";
import HomePage from "./components/HomePage";
import BookTicket from "./components/BookTicket";
import StudentPass from "./components/StudentPass";
import Complaint from "./components/Complaint";
import MyTickets from "./components/MyTickets";
import TicketDetails from "./components/TicketDetails";
import PaymentHistory from "./components/PaymentHistory";
import PassDetails from "./components/PassDetails";
import AdminDashboard from "./components/AdminDashboard";
import MyStudentPasses from "./components/MyStudentPasses";
import MyComplaints from "./components/MyComplaints";
import AdminBookingsList from "./components/AdminBookingsList";
import AdminPaymentsList from "./components/AdminPaymentsList";
import AdminPassesList from "./components/AdminPassesList";
import AdminVerificationsList from "./components/AdminVerificationsList";
import AdminComplaintsList from "./components/AdminComplaintsList";
import AdminQRTicketsList from "./components/AdminQRTicketsList";
import "./app.css";

type ViewName =
 | "home" | "book-ticket" | "student-pass" | "complaint"
 | "my-tickets" | "ticket-details" | "payment-history" | "pass-details"
 | "admin-dashboard" | "my-student-passes" | "my-complaints"
 | "admin-bookings" | "admin-payments" | "admin-student-passes"
 | "admin-student-verifications" | "admin-complaints" | "admin-qr-tickets";

interface ViewState { view: ViewName; recordId: string | null; }

function getViewFromUrl(): ViewState {
 const params = new URLSearchParams(window.location.search);
 return { view: (params.get("view") as ViewName) || "home", recordId: params.get("id") || null };
}

export default function App() {
 const [currentView, setCurrentView] = useState<ViewState>(getViewFromUrl);

 useEffect(() => {
 const onPopState = () => setCurrentView(getViewFromUrl());
 window.addEventListener("popstate", onPopState);
 return () => window.removeEventListener("popstate", onPopState);
 }, []);

 const navigateToView = useCallback((viewName: string, recordId?: string | null) => {
 const params = new URLSearchParams({ view: viewName });
 if (recordId) params.set("id", recordId);
 const relativePath = `${window.location.pathname}?${params}`;
 const title = `Metro - ${viewName.charAt(0).toUpperCase() + viewName.slice(1)}`;
 if (window.self !== window.top) {
 (window as any).CustomEvent.fireTop("magellanNavigator.permalink.set", { relativePath, title });
 }
 window.history.pushState({ viewName, recordId }, "", relativePath);
 document.title = title;
 setCurrentView({ view: viewName as ViewName, recordId: recordId || null });
 }, []);

 const { view, recordId } = currentView;

 const renderView = () => {
 switch (view) {
 case "book-ticket": return <BookTicket navigateToView={navigateToView} />;
 case "student-pass": return <StudentPass navigateToView={navigateToView} />;
 case "complaint": return <Complaint navigateToView={navigateToView} />;
 case "my-tickets": return <MyTickets navigateToView={navigateToView} />;
 case "ticket-details": return <TicketDetails recordId={recordId} navigateToView={navigateToView} />;
 case "payment-history": return <PaymentHistory navigateToView={navigateToView} />;
 case "pass-details": return <PassDetails navigateToView={navigateToView} />;
 case "admin-dashboard": return <AdminDashboard navigateToView={navigateToView} />;
 case "my-student-passes": return <MyStudentPasses navigateToView={navigateToView} />;
 case "my-complaints": return <MyComplaints navigateToView={navigateToView} />;
 case "admin-bookings": return <AdminBookingsList navigateToView={navigateToView} />;
 case "admin-payments": return <AdminPaymentsList navigateToView={navigateToView} />;
 case "admin-student-passes": return <AdminPassesList navigateToView={navigateToView} />;
 case "admin-student-verifications": return <AdminVerificationsList navigateToView={navigateToView} />;
 case "admin-complaints": return <AdminComplaintsList navigateToView={navigateToView} />;
 case "admin-qr-tickets": return <AdminQRTicketsList navigateToView={navigateToView} />;
 default: return <HomePage navigateToView={navigateToView} />;
 }
 };

 return (
 <div className="metro-app">
 <Navigation currentView={view} navigateToView={navigateToView} />
 <main className="metro-app__content">{renderView()}</main>
 </div>
 );
}
",".metro-admin {
 padding: 24px;
 max-width: 1100px;
 margin: 0 auto;
}

.metro-admin__title {
 font-size: 24px;
 color: #1a237e;
 margin: 0 0 24px;
}

.metro-admin__kpis {
 display: grid;
 grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
 gap: 12px;
 margin-bottom: 32px;
}

.metro-admin__kpi-card {
 background: #ffffff;
 border-radius: 8px;
 padding: 16px;
 box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
 border-left: 4px solid #1a237e;
